import fs from "node:fs/promises";
import path from "node:path";
import vm from "node:vm";
import { fileURLToPath } from "node:url";

const root = path.dirname(fileURLToPath(import.meta.url));

const sourceFiles = [
  "components/icons.jsx",
  "components/charts.jsx",
  "components/state.jsx",
  "components/layout.jsx",
  "components/dashboard.jsx",
  "components/log.jsx",
  "components/views.jsx",
  "components/sessions.jsx",
  "components/exercise-modal.jsx",
  "components/phase-progress.jsx",
  "components/settings.jsx",
  "components/strength.jsx",
  "tweaks-panel.jsx",
  "app.jsx"
];

const sandbox = { console };
sandbox.window = sandbox;
sandbox.self = sandbox;
sandbox.globalThis = sandbox;
vm.createContext(sandbox);

const babelSource = await fs.readFile(path.join(root, "vendor/babel.min.js"), "utf8");
vm.runInContext(babelSource, sandbox, { filename: "vendor/babel.min.js" });

if (!sandbox.Babel) {
  throw new Error("Babel standalone did not initialize");
}

const chunks = [];
for (const file of sourceFiles) {
  const input = await fs.readFile(path.join(root, file), "utf8");
  const result = sandbox.Babel.transform(input, {
    filename: file,
    sourceType: "script",
    presets: [
      ["env", { modules: false, targets: { ie: "11" } }],
      ["react", { runtime: "classic" }]
    ],
    comments: false,
    compact: false
  });

  chunks.push(`/* ---- ${file} ---- */\n${result.code}\n`);
}

const output = [
  "/* Generated by dashboard/build-bundle.mjs. Do not edit this file directly. */",
  ...chunks
].join("\n");

await fs.writeFile(path.join(root, "app.bundle.js"), output);
console.log(`Built app.bundle.js from ${sourceFiles.length} source files.`);
